import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        if a < b < c:
            out.append('Increasing')
        elif a > b > c:
            out.append('Decreasing')
        else:
            out.append('Neither')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

